"""Reference patches for template-match-based detection.

Each TemplateRef carries a bbox + base64+zlib of the raw RGB bytes
(3 bytes per pixel, row-major). Captured from the user's reference
shots in `arpg_stuff/` (2026-05-06 calibration).
"""

from __future__ import annotations

import base64
import zlib
from dataclasses import dataclass


@dataclass(frozen=True)
class TemplateRef:
    name: str
    bbox: tuple[int, int, int, int]   # (x1, y1, x2_excl, y2_excl)
    pixels: tuple[tuple[int, int, int], ...]
    rgb_tolerance: int
    match_threshold_pct: float


def _decode(b64: str) -> tuple[tuple[int, int, int], ...]:
    raw = zlib.decompress(base64.b64decode(b64))
    return tuple(
        (raw[i], raw[i + 1], raw[i + 2]) for i in range(0, len(raw), 3)
    )


# --- BOSS bar reference (HP-independent UI frame) ----
_BOSS_B64 = ""
BOSS_REF = TemplateRef(
    name="boss",
    bbox=(1272, 84, 1294, 107),
    pixels=_decode(_BOSS_B64),
    rgb_tolerance=30,
    match_threshold_pct=80.0,
)

# --- MOUNT indicator reference ----
_MOUNT_B64 = ""
MOUNT_REF = TemplateRef(
    name="mounted",
    bbox=(1030, 1289, 1096, 1321),
    pixels=_decode(_MOUNT_B64),
    rgb_tolerance=30,
    match_threshold_pct=70.0,
)
